def representative_thetas(theta_values):
    theta_values = np.array(sorted(theta_values), dtype=np.float64)
    if len(theta_values) <= 6:
        return theta_values
    idx = np.linspace(0, len(theta_values) - 1, 6).round().astype(int)
    return theta_values[np.unique(idx)]


def plot_fanh_by_theta(df: pd.DataFrame, result: dict, outdir: Path, dpi: int):
    reps = representative_thetas(result["theta_values"])
    fig, axes = plt.subplots(2, 3, figsize=(14.0, 8.2))
    for ax, theta in zip(axes.flat, reps):
        sub = df[np.isclose(df["theta"], theta, atol=5.0e-4, rtol=0.0)].copy().sort_values("x")
        idx = nearest_theta(result["theta_values"], theta)
        gamma_theta = result["gamma_theta"][idx]
        xfit = np.geomspace(float(np.min(sub["x"])), float(np.max(sub["x"])), 300)
        f0 = float(sub["F0"].iloc[0])
        finf = float(result["F_inf"][idx])
        f_univ = finf / np.maximum(f0, 1.0e-18) + f0 / (np.power((xfit) / T_OSC, 1.5) * (1.0 + np.power(xfit / max(result["t_c"], 1.0e-12), result["r"])))
        for h, hsub in sub.groupby("H", sort=True):
            ax.plot(hsub["x"], hsub["fanh"], "o", ms=3.0, label=rf"$H={h:g}$")
            ax.plot(xfit, np.power(float(h), gamma_theta) * f_univ, lw=1.5)
        ax.set_xscale("log")
        ax.set_yscale("log")
        ax.set_xlabel(r"$x$")
        ax.set_ylabel("fanh")
        ax.set_title(rf"$\theta={theta:.3f}$")
        ax.grid(alpha=0.25)
    axes.flat[0].legend(frameon=False, fontsize=8)
    fig.tight_layout()
    fig.savefig(outdir / "fanh_vs_x_by_theta.png", dpi=dpi)
    plt.close(fig)


