def plot_residual_heatmap(df: pd.DataFrame, result: dict, outdir: Path, dpi: int):
    theta_values = np.array(sorted(df["theta"].unique()), dtype=np.float64)
    x = result["x"]
    resid = (df["xi"].to_numpy(dtype=np.float64) - result["xi_fit"]) / np.maximum(result["xi_fit"], 1.0e-12)
    xbins = np.geomspace(float(np.min(x)), float(np.max(x)), 40)
    heat = np.full((len(theta_values), len(xbins) - 1), np.nan, dtype=np.float64)
    for i, theta in enumerate(theta_values):
        mask_theta = np.isclose(df["theta"], theta, atol=5.0e-4, rtol=0.0)
        for j in range(len(xbins) - 1):
            mask_bin = mask_theta & (x >= xbins[j]) & (x < xbins[j + 1])
            if np.any(mask_bin):
                heat[i, j] = float(np.mean(resid[mask_bin]))
    fig, ax = plt.subplots(figsize=(8.8, 4.8))
    pcm = ax.pcolormesh(xbins, np.arange(len(theta_values) + 1), heat, cmap="coolwarm", vmin=-0.2, vmax=0.2, shading="auto")
    ax.set_xscale("log")
    ax.set_xlabel(r"$x$")
    ax.set_ylabel(r"$\theta$ index")
    ax.set_yticks(np.arange(len(theta_values)) + 0.5)
    ax.set_yticklabels([f"{th:.3f}" for th in theta_values])
    ax.set_title("Relative residual heatmap")
    fig.colorbar(pcm, ax=ax, label=r"$(\xi_{\rm data}-\xi_{\rm model})/\xi_{\rm model}$")
    fig.tight_layout()
    fig.savefig(outdir / "residual_heatmap_twoexp.png", dpi=dpi)
    plt.close(fig)


def plot_inversion(df: pd.DataFrame, result: dict, gamma_mode: str, outdir: Path, dpi: int):
    for theta in result["theta_values"]:
        sub = df[np.isclose(df["theta"], theta, atol=5.0e-4, rtol=0.0)].copy().sort_values("x")
        idx = nearest_theta(result["theta_values"], theta)
        gamma_theta = result["gamma_theta"][idx]
        fanh_scaled = sub["fanh"].to_numpy(dtype=np.float64) / np.power(sub["H"].to_numpy(dtype=np.float64), gamma_theta)
        x = sub["x"].to_numpy(dtype=np.float64)
        f0 = sub["F0"].to_numpy(dtype=np.float64)
        xi_adj = np.power((x) / T_OSC, 1.5) * fanh_scaled / np.maximum(f0, 1.0e-18)
        T = np.power((x) / T_OSC, 1.5) * result["F_inf"][idx] / np.maximum(f0 * f0, 1.0e-18)
        D = xi_adj - T
        mask = (D > 0.05) & (D < 0.95) & np.isfinite(D) & (x > 0.0)
        if np.sum(mask) < 3:
            continue
        xfit = x[mask]
        Y = 1.0 / D[mask] - 1.0
        good = np.isfinite(Y) & (Y > 0.0)
        if np.sum(good) < 3:
            continue
        lx = np.log(xfit[good])
        ly = np.log(Y[good])
        slope, _ = slope_fit_logH(lx, ly)
        intercept = float(np.mean(ly) - slope * np.mean(lx))
        fig, ax = plt.subplots(figsize=(5.6, 4.2))
        ax.plot(lx, ly, "o", ms=3.0, label="data")
        xx = np.linspace(float(np.min(lx)), float(np.max(lx)), 200)
        ax.plot(xx, intercept + slope * xx, color="tab:red", lw=1.8, label=rf"fit, slope={slope:.3f}")
        ax.set_xlabel(r"$\log x$")
        ax.set_ylabel(r"$\log Y$")
        ax.set_title(rf"Inversion, $\theta={theta:.3f}$")
        ax.grid(alpha=0.25)
        ax.legend(frameon=False, fontsize=8)
        fig.tight_layout()
        fig.savefig(outdir / f"logY_vs_logx_theta_{theta:.3f}.png", dpi=dpi)
        plt.close(fig)


def plot_beta_gamma_scan(df: pd.DataFrame, result: dict, beta_init: float, gamma_init: float, outdir: Path, dpi: int, gamma_mode: str):
    if gamma_mode != "scalar":
        return
    beta_grid = np.linspace(0.9 * beta_init, 1.1 * beta_init, 25) if abs(beta_init) > 1.0e-10 else np.linspace(-0.1, 0.1, 25)
    gamma_grid = np.linspace(gamma_init - 0.5, gamma_init + 0.5, 25)
    theta_values = result["theta_values"]
    heat = np.full((len(gamma_grid), len(beta_grid)), np.nan, dtype=np.float64)
    base_params = np.asarray(result["params"], dtype=np.float64)
    gamma_idx = 1 if len(base_params) == len(theta_values) + 4 else 0
    tc_idx = gamma_idx + 1
    r_idx = gamma_idx + 2
    free_beta = len(base_params) == len(theta_values) + 4
    for i, gamma in enumerate(gamma_grid):
        for j, beta in enumerate(beta_grid):
            params = base_params.copy()
            if free_beta:
                params[0] = beta
                params[1] = gamma
                rec = xi_model(df, theta_values, params, None, "scalar")
            else:
                params[0] = gamma
                rec = xi_model(df, theta_values, params, beta, "scalar")
            resid = (rec["xi_fit"] - df["xi"].to_numpy(dtype=np.float64)) / np.maximum(df["xi"].to_numpy(dtype=np.float64), 1.0e-12)
            heat[i, j] = float(np.sum(np.square(resid)))
    fig, ax = plt.subplots(figsize=(6.2, 4.8))
    pcm = ax.pcolormesh(beta_grid, gamma_grid, heat, shading="auto", cmap="viridis")
    ax.axvline(beta_init, color="white", ls="--", lw=1.2)
    ax.axhline(gamma_init, color="white", ls="--", lw=1.2)
    ax.set_xlabel(r"$\beta$")
    ax.set_ylabel(r"$\gamma$")
    ax.set_title("Approximate beta-gamma scan")
    fig.colorbar(pcm, ax=ax, label="RSS")
    fig.tight_layout()
    fig.savefig(outdir / "beta_gamma_scan.png", dpi=dpi)
    plt.close(fig)


def evaluate_original_collapse_model(df: pd.DataFrame, theta_values: np.ndarray, beta_init: float, collapse_fit_payload: dict):
    if "F_inf" not in collapse_fit_payload:
        return {"AIC": np.nan, "BIC": np.nan, "rel_rmse": np.nan, "rss_frac": np.nan}
    finf = []
    for th in theta_values:
        try:
            entry = theta_key_lookup(collapse_fit_payload["F_inf"], float(th))
        except KeyError:
            return {"AIC": np.nan, "BIC": np.nan, "rel_rmse": np.nan, "rss_frac": np.nan}
        finf.append(float(entry["value"]))
    params = np.asarray([0.0, float(collapse_fit_payload.get("t_c", 1.5)), float(collapse_fit_payload.get("r", 1.5)), *finf], dtype=np.float64)
    rec = xi_model(df, theta_values, params, beta_init, "scalar")
    resid = (rec["xi_fit"] - df["xi"].to_numpy(dtype=np.float64)) / np.maximum(df["xi"].to_numpy(dtype=np.float64), 1.0e-12)
    rss = float(np.sum(np.square(resid)))
    n = len(df)
    k = len(params)
    aic = float(n * math.log(max(rss, 1.0e-18) / n) + 2.0 * k)
    bic = float(n * math.log(max(rss, 1.0e-18) / n) + k * math.log(n))
    return {"AIC": aic, "BIC": bic, "rel_rmse": rel_rmse(df["xi"].to_numpy(dtype=np.float64), rec["xi_fit"]), "rss_frac": rss}


def main():
    args = parse_args()
    outdir = (ROOT / args.outdir).resolve()
    outdir.mkdir(parents=True, exist_ok=True)

    try:
        rho_path = resolve_first_existing(RHO_CANDIDATES, args.rho)
        best_beta_path = resolve_first_existing(BEST_BETA_CANDIDATES, args.best_beta)
        collapse_fit_path = resolve_first_existing(GLOBAL_FIT_CANDIDATES, args.collapse_fit)
        finf_tail_path = resolve_first_existing(FINF_TAIL_CANDIDATES, args.finf_tail)
        raw_lattice_path = resolve_first_existing(LATTICE_RAW_CANDIDATES, args.lattice_raw)
        ode_path = None if args.skip_ode else resolve_first_existing(ODE_CANDIDATES, args.ode)

        if rho_path is None:
            raise FileNotFoundError("Missing rho_noPT_data.txt")
        if best_beta_path is None:
            raise FileNotFoundError("Missing results_collapse/best_beta.json")

        beta_payload = json.loads(best_beta_path.read_text())
        beta_init = float(beta_payload["beta"])
        collapse_fit_payload = json.loads(collapse_fit_path.read_text()) if collapse_fit_path is not None else {}

        target_h = sorted(set(float(h) for h in args.h_values))
        f0_table = load_f0_table(rho_path, target_h)
        f0_table.to_csv(outdir / "F0_table.csv", index=False)

        lattice_df = load_lattice_data(raw_lattice_path, args.fixed_vw, target_h)
        frames = [lattice_df]
        if ode_path is not None:
            ode_df = load_optional_ode(ode_path, args.fixed_vw, target_h)
            if ode_df is not None and not ode_df.empty:
                frames.append(ode_df)
        df = pd.concat(frames, ignore_index=True)
        df = merge_f0(df, f0_table)
        df = df[np.isfinite(df["F0"]) & (df["F0"] > 0.0)].copy()
        if df.empty:
            raise RuntimeError("No valid xi rows after merging F0.")

        df = compute_x(df, beta_init)
        gamma_per_x, gamma_by_theta, gamma_pooled, cell_df = build_gamma_tables(df, args.grid_n, outdir)
        cos_fit = fit_gamma_theta_cos(gamma_by_theta)
        plot_gamma_vs_theta(gamma_by_theta, cos_fit, outdir, args.dpi)
        plot_gamma_pooled(cell_df, gamma_pooled, outdir, args.dpi)

        theta_values = np.array(sorted(df["theta"].unique()), dtype=np.float64)
        init_tc = float(collapse_fit_payload.get("t_c", 1.5))
        init_r = float(collapse_fit_payload.get("r", 1.5))
        init_gamma = float(gamma_pooled["gamma"]) if np.isfinite(gamma_pooled["gamma"]) else 0.0

        init_finf = np.full(len(theta_values), 1.0e-6, dtype=np.float64)
        if finf_tail_path is not None and finf_tail_path.exists():
            finf_df = pd.read_csv(finf_tail_path)
            for i, th in enumerate(theta_values):
                sub = finf_df[np.isclose(finf_df["theta"], th, atol=5.0e-4, rtol=0.0)]
                if not sub.empty and np.isfinite(sub["F_inf_tail"].iloc[0]):
                    init_finf[i] = max(float(sub["F_inf_tail"].iloc[0]), 1.0e-8)
        if "F_inf" in collapse_fit_payload:
            for i, th in enumerate(theta_values):
                try:
                    entry = theta_key_lookup(collapse_fit_payload["F_inf"], float(th))
                    init_finf[i] = max(float(entry["value"]), 1.0e-8)
                except KeyError:
                    pass

        scalar_result = fit_twoexp_model(df, theta_values, beta_init, init_gamma, init_tc, init_r, init_finf, args.free_beta, "scalar")
        scalar_payload = extract_fit_payload(scalar_result, beta_init, args.free_beta, "scalar")
        save_json(outdir / "global_twoexp_fit.json", scalar_payload)

        cos_payload = None
        if not args.scalar_only:
            cos_result = fit_twoexp_model(df, theta_values, beta_init, init_gamma, init_tc, init_r, init_finf, args.free_beta, "cos")
            cos_payload = extract_fit_payload(cos_result, beta_init, args.free_beta, "cos")

        bootstrap_payload = bootstrap_twoexp(
            df,
            scalar_result,
            scalar_payload["beta"],
            args.free_beta,
            "scalar",
            args.bootstrap,
            args.bootstrap_jobs,
            args.bootstrap_seed,
        )
        save_json(outdir / "bootstrap_twoexp_fit.json", bootstrap_payload)

        plot_fanh_by_theta(df.assign(x=scalar_result["x"]), scalar_result, outdir, args.dpi)
        plot_collapse_overlay(df.assign(x=scalar_result["x"]), scalar_result, outdir, args.dpi)
        plot_residual_heatmap(df.assign(x=scalar_result["x"]), scalar_result, outdir, args.dpi)
        plot_inversion(df.assign(x=scalar_result["x"]), scalar_result, "scalar", outdir, args.dpi)
        plot_beta_gamma_scan(df, scalar_result, beta_init, scalar_payload["gamma"], outdir, args.dpi, "scalar")

        original_eval = evaluate_original_collapse_model(df, theta_values, beta_init, collapse_fit_payload)
        original_aic = float(original_eval["AIC"])
        original_bic = float(original_eval["BIC"])
        original_rmse = float(original_eval["rel_rmse"])
        model_comp = {
            "original_collapsed_model": {"AIC": original_aic, "BIC": original_bic, "rel_rmse": original_rmse},
            "scalar_gamma_model": {"AIC": scalar_payload["AIC"], "BIC": scalar_payload["BIC"], "rel_rmse": scalar_payload["rel_rmse"]},
            "delta_AIC_scalar_minus_original": float(scalar_payload["AIC"] - original_aic) if np.isfinite(original_aic) else np.nan,
            "delta_BIC_scalar_minus_original": float(scalar_payload["BIC"] - original_bic) if np.isfinite(original_bic) else np.nan,
        }
        if cos_payload is not None:
            model_comp["gamma_cos_model"] = {"AIC": cos_payload["AIC"], "BIC": cos_payload["BIC"], "rel_rmse": cos_payload["rel_rmse"]}
            model_comp["delta_AIC_cos_minus_scalar"] = float(cos_payload["AIC"] - scalar_payload["AIC"])
            model_comp["delta_BIC_cos_minus_scalar"] = float(cos_payload["BIC"] - scalar_payload["BIC"])
        save_json(outdir / "model_comparison.json", model_comp)

        final_summary = {
            "status": "ok",
            "beta_used": scalar_payload["beta"],
            "beta_from_collapse": beta_init,
            "gamma_pooled": gamma_pooled["gamma"],
            "gamma_pooled_ci95": gamma_pooled["gamma_ci95"],
            "p_value_gamma_eq_0": gamma_pooled["p_value_gamma_eq_0"],
            "twoexp_fit": {
                "gamma": scalar_payload["gamma"],
                "t_c": scalar_payload["t_c"],
                "r": scalar_payload["r"],
                "rel_rmse": scalar_payload["rel_rmse"],
                "AIC": scalar_payload["AIC"],
                "BIC": scalar_payload["BIC"],
            },
            "model_comparison": model_comp,
            "gamma_theta_cos_fit": None if args.scalar_only else cos_fit,
        }
        save_json(outdir / "final_summary.json", final_summary)
        print(json.dumps(to_native(final_summary), indent=2, sort_keys=True))
        return 0
    except Exception as exc:
        return error_exit(outdir, str(exc))


if __name__ == "__main__":
    raise SystemExit(main())
